// friday13.cs — Friday the 13th explorer (proleptic Gregorian)

// 1) Find the earliest Friday the 13th starting from 0001-01-01
var date = new DateTime(1, 1, 13); // start on the 13th of Jan 0001
while (date.DayOfWeek != DayOfWeek.Friday)
    date = date.AddMonths(1);

Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd} ({date.DayOfWeek})");

// 2) Count Friday the 13ths in a full 400-year cycle (0001-01-01 to 0400-12-31)
//    The Gregorian calendar repeats every 400 years.
int count = 0;
var scan = new DateTime(1, 1, 13);
var end = new DateTime(400, 12, 31);

while (scan <= end)
{
    if (scan.DayOfWeek == DayOfWeek.Friday)
        count++;
    scan = scan.AddMonths(1);
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

// 3) Bonus: distribution by day-of-week for the 13th
var dayCount = new int[7];
scan = new DateTime(1, 1, 13);
while (scan <= end)
{
    dayCount[(int)scan.DayOfWeek]++;
    scan = scan.AddMonths(1);
}

Console.WriteLine("\n13th-of-month distribution over 400 years:");
foreach (DayOfWeek dow in Enum.GetValues<DayOfWeek>())
    Console.WriteLine($"  {dow,-10} {dayCount[(int)dow],4}  {dayCount[(int)dow] / 4800.0 * 100:F2}%");

